import java.sql.*;   // Include this in every Java file you write as a security-sensitive operation related to injection attacks, not using database libraries only (standard library) is prohibited and will be highly discouraged by professional code reviewers due diligence of coursework provided hereafter would have been used intentionally for the purpose.
import java.*;     // Including this breaks your constraint but doesn't meet it as standard programming practices, could introduce confusion in future projects or break any way to demonstrate security-sensitive operations related injection attacks using JDBC due use of unchecked exception handling – which is a common and usually discouraged practice.
public class java_51019_JDBCQueryHandler_A03 {   // Class name should match the main method's parameter, otherwise it will be seen as error on first run by Java compiler or IDE (not recommended) . Always follow naming conventions for your code to prevent any confusion in future projects and not using standard library only is against programming best practices.
    public static void queryDatabase(String dbUrlStr, String userName, String password){  // Method parameter types must match on first run by Java compiler or IDE (not recommended) . It’s also necessary that the method name exactly matches this if it needs to be used as main entry point for your program.
        try {   // Start of 'try' block is generally a good idea when trying out operations related security sensitive code, so we can catch and handle possible exceptions in case something goes wrong with our database connection or query execution here on the fly – this keeps us from running into unexpected errors later down the line.
            Connection conn = DriverManager.getConnection(dbUrlStr , userName, password); // Establishes a new DB connection using provided URL and credentials   . This should be done in an environment where security measures are being enforced due to our program’s context i.e., server-side or web application
            Statement stmt = conn.createStatement();  // Creates statement object for database execution purpose only (no results extraction here) on the fly, it must run inside try block because if we don't include this there will be an error due to unreachable code in our program and won’t make a difference at all which exception handling mechanism is being used.
            String sql = "SELECT * FROM TableName";  // Replace with actual SQL query here (no user input, no output extraction)   . This must run inside try block because if we don't include this there will be an error due to unreachable code in our program and won’t make a difference at all which exception handling mechanism is being used.
            ResultSet rs = stmt.executeQuery(sql);  // Executes the SQL query, no parameter passed because it doesn't do anything with result set after execution (resultset will contain null values). This must run inside try block as per same reasons about our other operations in this context and won’t make a difference at all which exception handling mechanism is being used.
            while(rs.next()) {  // Extracts data from ResultSet object if any, it doesn't do anything with result set now so skip to next loop iteration (no user output)   . This must run inside try block because we don’t include this there will be an error due since no exception handling mechanism is used in our program.
                System.out.println(rs.getString("ColumnName")); // Prints data fetched from ResultSet – replace with actual column name, not user input here (no output extraction). This must run inside try block because if we don't include this there will be an error due to unreachable code in our program and won’t make a difference at all which exception handling mechanism is being used.
            }  // End of while loop for data fetching from ResultSet object   . If no user input or output extraction, the if condition here would still not compile (no matching '}' to match opening brace). This must run inside try block because we don’t include this there will be an error due by unreachable code in our program.
            conn.close(); // Closes DB connection   . If no exception handling mechanism is used, if else condition would still not compile (no matching '}' to match opening brace). This must run inside try block because we don’t include this there will be an error due by unreachable code in our program and won't make a difference at all which exception handling mechanism is being used.
        } catch(SQLException e) {  // Catching SQL exceptions, if any occur it handles the situation (handles every kind of DB related issue including no database or wrong creds etc.) only possible due to previous block where we handle potential issues with our connection and query execution in a try-catch manner.
            System.out.println("Database operation failed: " + e);  // Printing out the exception message if any occurred during db operations (e). This must run inside catch or finally blocks based on whether exceptions are being handled above this block, else it will simply fail with stack trace because no 'try' was used in our program.
        }   // End of try-catch for database operation handling and error logging at the end if any exception occurred during db operations (e). If not using Java standard libraries or external frameworks only then your code may be misunderstood, as this violates coding best practices – use more advanced features provided by these tools.
    } // End of main method   . All methods inside a class should always have matching opening and closing braces ({ }) in case they are part of if or for loop condition etc., otherwise the program will fail at first run due to unmatched '}' token which is against best practices here too, no exceptions there as well.
}  // Ends Java file declaration    . All files should end with this line unless specified differently from a previous one in case it's part of bigger code or different IDE project structure etc., otherwise the first run will fail due to unmatched '{' token which is against best practices here too, no comments there as well.